import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"安裝模組","description":"Fabric 模組安裝的逐步指南","frontmatter":{"title":"安裝模組","description":"Fabric 模組安裝的逐步指南","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.4/players/installing-mods.md","filePath":"versions/1.21.4/translated/zh_tw/players/installing-mods.md","lastUpdated":1760721669000}`);var s={name:`zh_tw/1.21.4/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">安裝模組 <a class="header-anchor" href="#h1" aria-label="Permalink to “安裝模組”">​</a></h1><p>這個指南將引導你使用 Minecraft 啟動器安裝 Fabric 模組。</p><p>對於第三方啟動器，您應該查閱他們的文件。</p><h2 id="1-download-the-mod" tabindex="-1">1. 下載模組 <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. 下載模組”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>你應該只從你信任的來源下載模組。 如需更多關於尋找模組的資訊，請參閱<a href="./finding-mods">尋找模組</a>指南。 如需更多關於尋找模組的資訊，請參閱<a href="./finding-mods">尋找模組</a>指南。</p></div><p>大部分的模組都需要 Fabric API，它可以從 <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> 或 <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>下載。</p><p>下載模組時，請確保：</p><ul><li>它們能在你想玩的 Minecraft 版本上執行。 例如，一個在 1.20 上執行的模組可能無法在 1.20.2 上執行。 例如，一個在 1.20 上執行的模組可能無法在 1.20.2 上執行。 例如，一個在 1.20 上執行的模組可能無法在 1.20.2 上執行。</li><li>它是為 Fabric 製作，而不是其他模組載入器。</li><li>此外，它們適用於正確的 Minecraft 版本（Java 版）。</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. 將模組移動到 <code>mods</code> 資料夾 <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. 將模組移動到 mods 資料夾”">​</a></h2><p>各個作業系統中，模組資料夾的位置如下所示：</p><p>您可以將這些路徑貼上到檔案總管的路徑列中，以便快速導航到該資料夾。</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>找到 <code>mods</code> 資料夾後，您可以將模組 <code>.jar</code> 檔案移動到其中。</p><p><img src="/assets/players/installing-mods.png" alt="mods 資料夾中已安裝的模組" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. 你完成了！ <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. 你完成了！”">​</a></h2><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="已選擇 Fabric 設定檔的 Minecraft 啟動器" loading="lazy"></p><p>將模組移動到 <code>mods</code> 資料夾後，您可以開啟 Minecraft 啟動器，並從左下方的下拉式選單中選擇 Fabric 設定檔，然後按下開始遊戲！</p><h2 id="troubleshooting" tabindex="-1">疑難排解 <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “疑難排解”">​</a></h2><p>如果你在依照本指南操作時遇到任何問題，你可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 頻道中尋求幫助。</p><p>您也可以嘗試透過閱讀疑難排解頁面自行解決問題：</p><ul><li><a href="./troubleshooting/crash-reports">崩潰報告</a></li><li><a href="./troubleshooting/uploading-logs">上傳記錄檔</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};